
'use client';

import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { useToast } from '@/hooks/use-toast';
import ImageUploader from '@/components/app/image-uploader';
import { createKissVideoAction } from '@/app/actions';
import { Button } from '@/components/ui/button';
import { Loader2, Wand2, ArrowLeft, Eye, Download } from 'lucide-react';
import { Progress } from "@/components/ui/progress";
import Image from 'next/image';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import type { UploadMode } from '@/components/app/image-uploader';
import SubscriptionDialog from '@/components/app/subscription-dialog';
import { fuseImages, type FuseImagesInput } from '@/ai/flows/fuse-images-flow';
import { useAuth } from '@/contexts/auth-context';
import { checkUserSubscription, type UserProfile, decrementUserCredits } from '@/lib/firebase/db';

type AppState = 'form' | 'loading' | 'result';
type LoadingReason = 'generating' | 'configuring';

function PageContent() {
  const { user, loading: authLoading } = useAuth();
  const searchParams = useSearchParams();
  const router = useRouter();
  const [appState, setAppState] = useState<AppState>('form');
  const [loadingReason, setLoadingReason] = useState<LoadingReason>('generating');
  const [uploadMode, setUploadMode] = useState<UploadMode>('two');
  const [image1, setImage1] = useState<string | null>(null);
  const [image2, setImage2] = useState<string | null>(null);
  const [sourceImageUrl, setSourceImageUrl] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [canGenerate, setCanGenerate] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isSubDialogOpen, setIsSubDialogOpen] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const { toast } = useToast();

  // Effect to handle post-payment subscription activation
  useEffect(() => {
    async function handlePaymentSuccess() {
        if (searchParams.get('paid') === 'true' && user) {
            try {
                // Fetch updated profile after login/activation flow
                const profile = await checkUserSubscription(user.uid);
                setUserProfile(profile);
                
                toast({
                    title: 'Payment Successful!',
                    description: 'Your account is being configured. Starting video generation...',
                });
                
                // Clear the 'paid' query param from the URL
                router.replace('/', { scroll: false }); 

                // Check for saved images and start generation
                const postSignupData = sessionStorage.getItem('postSignupGeneration');
                if (postSignupData) {
                    sessionStorage.removeItem('postSignupGeneration');
                    const { image1: savedImage1, image2: savedImage2, uploadMode: savedUploadMode } = JSON.parse(postSignupData);
                    
                    setLoadingReason('configuring');
                    setAppState('loading');
                    
                    // The `true` flag forces the paid/real generation flow
                    await handleGenerate(true, { image1DataUri: savedImage1, image2DataUri: savedImage2, uploadMode: savedUploadMode });
                }
            } catch (error) {
                console.error("Error processing post-payment:", error);
                toast({ variant: 'destructive', title: 'Error', description: 'There was an issue fetching your updated profile.' });
            }
        }
    }
    if (user && !authLoading) {
        handlePaymentSuccess();
    }
  }, [searchParams, user, authLoading, router, toast]);
  
  // Effect to fetch user profile
  useEffect(() => {
    async function fetchUserProfile() {
      if (user) {
        const profile = await checkUserSubscription(user.uid);
        setUserProfile(profile);
      } else {
        setUserProfile(null);
      }
    }
    fetchUserProfile();
  }, [user]);

  // Handle case where user returns from Whop but is not logged in
  useEffect(() => {
    if (searchParams.get('paid') === 'true' && !user && !authLoading) {
        toast({
            title: "Almost there!",
            description: "Please sign in or create an account to activate your subscription."
        });
        // Pass the 'paid' param to the login page so we know to activate subscription after auth.
        router.push('/login?paid=true');
    }
  }, [searchParams, user, authLoading, router, toast]);


  useEffect(() => {
    const isReady = image1 && (uploadMode === 'single' || image2);
    setCanGenerate(!!isReady);
  }, [image1, image2, uploadMode]);

  useEffect(() => {
    let interval: NodeJS.Timeout | null = null;
    if (appState === 'loading') {
      setProgress(0);

      if (loadingReason === 'configuring') {
        const duration = 25000; // 25 seconds
        const steps = 100;
        const stepDuration = duration / steps;
        
        const slowRandomIncrement = () => {
          setProgress(prev => {
            if (prev >= 95) {
              if (interval) clearInterval(interval);
              return 95;
            }
            // A more gradual increment
            return Math.min(prev + (100/steps), 95);
          });
        };

        interval = setInterval(slowRandomIncrement, stepDuration);
      } else {
         const isPaidFlow = userProfile?.isSubscribed;
         const duration = isPaidFlow ? 1500 : (8000 / 20); 
         interval = setInterval(() => {
           setProgress(prev => {
             if (prev >= 95) {
               if (interval) clearInterval(interval);
               return 95;
             }
             return prev + 5;
           });
         }, duration);
      }
    }
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [appState, userProfile, loadingReason]);

  const handleGenerate = async (isPaidOverride = false, postSignupParams?: { image1DataUri: string, image2DataUri: string | null, uploadMode: UploadMode }) => {
    const effectiveImage1 = postSignupParams?.image1DataUri || image1;
    const effectiveImage2 = postSignupParams?.image2DataUri || image2;
    const effectiveUploadMode = postSignupParams?.uploadMode || uploadMode;

    if (!effectiveImage1 || (effectiveUploadMode === 'two' && !effectiveImage2)) {
      toast({
        variant: 'destructive',
        title: 'Missing Images',
        description: 'Please upload all required images before generating.',
      });
      return;
    }

    if (appState !== 'loading') {
        setAppState('loading');
        setLoadingReason('generating');
    }
    
    const isPaidFlow = userProfile?.isSubscribed || isPaidOverride;

    if (isPaidFlow) {
      if(userProfile && !isPaidOverride) {
        if (userProfile.credits <= 0) {
           toast({ variant: 'destructive', title: 'No Credits', description: 'You have no video credits left.' });
           setAppState('form');
           return;
        }
        await decrementUserCredits(userProfile.uid);
      }
      
      const result = await createKissVideoAction({
        image1DataUri: effectiveImage1!,
        image2DataUri: effectiveUploadMode === 'two' ? effectiveImage2! : undefined,
      });
      setProgress(100);

      if (result.error) {
        setAppState('form');
        toast({
          variant: 'destructive',
          title: 'Video Generation Failed',
          description: result.error,
        });
      } else if (result.videoDataUri && result.sourceImageDataUri) {
        setVideoUrl(result.videoDataUri);
        setSourceImageUrl(result.sourceImageDataUri);
        setAppState('result');
        // Refresh profile to show updated credits
        if (user) setUserProfile(await checkUserSubscription(user.uid));
      }

    } else {
      let sourceImage = effectiveImage1;
      if (effectiveUploadMode === 'two' && effectiveImage1 && effectiveImage2) {
        try {
          const fusedResult = await fuseImages({ image1DataUri: effectiveImage1, image2DataUri: effectiveImage2 });
          sourceImage = fusedResult.imageDataUri;
        } catch (e) {
            const message = e instanceof Error ? e.message : 'An unknown error occurred.';
            setAppState('form');
            toast({
                variant: 'destructive',
                title: 'Image Fusion Failed',
                description: `Could not combine images: ${message}`,
            });
            return;
        }
      }
      setTimeout(() => {
          setProgress(100);
          setSourceImageUrl(sourceImage);
          setAppState('result');
      }, 8000);
    }
  };
  
  const handleWatchVideo = () => {
    // Save state before redirecting or opening dialog
    const postSignupData = JSON.stringify({ image1, image2, uploadMode });
    sessionStorage.setItem('postSignupGeneration', postSignupData);

    if (!userProfile?.isSubscribed) {
      setIsSubDialogOpen(true);
    }
  }

  const handleDownload = () => {
    if (!videoUrl) return;
    const link = document.createElement('a');
    link.href = videoUrl;
    link.download = 'eternal-kiss.mp4';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleReset = () => {
    setAppState('form');
    setImage1(null);
    setImage2(null);
    setSourceImageUrl(null);
    setVideoUrl(null);
    setProgress(0);
    setLoadingReason('generating');
  };
  
  if (authLoading && !user) {
    // Show a loader only if we are not sure about auth state yet
     return (
        <div className="flex items-center justify-center h-full">
            <Loader2 className="h-12 w-12 animate-spin text-primary" />
        </div>
    );
  }

  const isPaidOrPostSignup = (userProfile?.isSubscribed || videoUrl);
  const hasCredits = userProfile && userProfile.credits > 0;

  return (
    <>
      <SubscriptionDialog 
        open={isSubDialogOpen} 
        onOpenChange={setIsSubDialogOpen}
       />
        <main className="flex-grow flex items-center justify-center p-4">
          <div className="w-full max-w-xl mx-auto">
            {appState === 'form' && (
              <div className="space-y-6">
                <div className="text-center">
                  <h2 className="text-5xl font-extrabold tracking-tighter bg-gradient-to-r from-pink-500 to-purple-600 bg-clip-text text-transparent">
                    Kiss Your Crush with AI
                  </h2>
                </div>
                <ImageUploader
                  mode={uploadMode}
                  setMode={setUploadMode}
                  image1={image1}
                  setImage1={setImage1}
                  image2={image2}
                  setImage2={setImage2}
                />
                <Button onClick={() => handleGenerate()} disabled={!canGenerate || appState === 'loading' || (userProfile?.isSubscribed && !hasCredits)} size="lg" className="w-full bg-gradient-to-r from-pink-500 to-purple-600 hover:from-pink-600 hover:to-purple-700 text-white">
                   {appState === 'loading' ? <Loader2 className="mr-2 h-5 w-5 animate-spin" /> : <Wand2 className="mr-2 h-5 w-5" />}
                  {userProfile?.isSubscribed && !hasCredits ? 'No Credits Remaining' : 'Generate Video'}
                </Button>
              </div>
            )}

            {appState === 'loading' && (
              <div className="flex flex-col items-center justify-center gap-6 text-center w-full max-w-md">
                  <Loader2 className="h-12 w-12 animate-spin text-pink-500" />
                  <div className="w-full space-y-2">
                      <h2 className="text-2xl font-semibold font-headline">
                        {loadingReason === 'configuring' ? 'Configuring your account...' : 'Creating your moment...'}
                      </h2>
                      <p className="text-muted-foreground">
                          This can take a minute. Please don't close this page.
                      </p>
                      <div className="flex items-center gap-2">
                        <Progress value={progress} className="w-full" showShimmer={true} />
                        <span className="text-sm font-medium text-muted-foreground w-10 text-right">{Math.round(progress)}%</span>
                      </div>
                  </div>
              </div>
            )}
            
            {appState === 'result' && (
              <Card className="w-full overflow-hidden shadow-2xl bg-gradient-to-br from-purple-50 via-pink-50 to-red-50">
                  <CardHeader className="text-center p-6">
                      <CardTitle className="text-3xl font-headline bg-gradient-to-r from-pink-500 to-purple-600 bg-clip-text text-transparent">
                        {isPaidOrPostSignup ? "Your Kiss is Ready!" : "Your Preview is Ready!"}
                      </CardTitle>
                      <CardDescription className="text-muted-foreground">
                        {isPaidOrPostSignup ? "Here is your moment of magic." : "Create an account to see your moment of magic."}
                      </CardDescription>
                  </CardHeader>

                  <CardContent className="p-4 pt-0">
                    <div className="relative rounded-lg overflow-hidden border-4 border-white shadow-lg aspect-video">
                        {isPaidOrPostSignup && videoUrl ? (
                            <video src={videoUrl} controls autoPlay loop className="w-full h-full object-cover" />
                        ) : (
                            <>
                                <Image
                                    src={sourceImageUrl || 'https://placehold.co/1280x720.png'}
                                    alt="Blurred preview of the generated video"
                                    width={1280}
                                    height={720}
                                    className="w-full h-full object-cover filter blur-lg"
                                />
                                <div className="absolute inset-0 bg-black/30 flex items-center justify-center">
                                    <Eye className="h-16 w-16 text-white/70" />
                                </div>
                            </>
                        )}
                    </div>
                </CardContent>

                <CardFooter className="p-4 pt-0 flex flex-col sm:flex-row gap-3">
                  <Button variant="outline" onClick={handleReset} className="w-full">
                    <ArrowLeft className="mr-2 h-4 w-4" />
                    Create Another
                  </Button>
                  {isPaidOrPostSignup ? (
                     <Button onClick={handleDownload} className="w-full bg-gradient-to-r from-pink-500 to-purple-600 hover:from-pink-600 hover:to-purple-700 text-white">
                        <Download className="mr-2 h-4 w-4" />
                        Download Video
                    </Button>
                  ) : (
                    <Button onClick={handleWatchVideo} className="w-full bg-gradient-to-r from-pink-500 to-purple-600 hover:from-pink-600 hover:to-purple-700 text-white">
                      <Wand2 className="mr-2 h-4 w-4" />
                      Watch Video
                    </Button>
                  )}
                </CardFooter>
              </Card>
            )}

          </div>
        </main>
    </>
  );
}

export default function Home() {
    return (
        <React.Suspense fallback={
            <div className="flex items-center justify-center h-screen">
                <Loader2 className="h-12 w-12 animate-spin text-primary" />
            </div>
        }>
            <PageContent />
        </React.Suspense>
    );
}
