"use client"

import * as React from "react"
import * as ProgressPrimitive from "@radix-ui/react-progress"

import { cn } from "@/lib/utils"

const Progress = React.forwardRef<
  React.ElementRef<typeof ProgressPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof ProgressPrimitive.Root> & { showShimmer?: boolean }
>(({ className, value, showShimmer = false, ...props }, ref) => (
  <ProgressPrimitive.Root
    ref={ref}
    className={cn(
      "relative h-4 w-full overflow-hidden rounded-full bg-secondary",
      className
    )}
    {...props}
  >
    <ProgressPrimitive.Indicator
      className={cn(
        "h-full w-full flex-1 bg-primary transition-all",
        showShimmer && "relative overflow-hidden"
      )}
      style={{ transform: `translateX(-${100 - (value || 0)}%)` }}
    >
        {showShimmer && (
            <div className="absolute inset-0 -skew-x-12 animate-shimmer items-center justify-center bg-gradient-to-r from-transparent via-white/30 to-transparent" />
        )}
    </ProgressPrimitive.Indicator>

  </ProgressPrimitive.Root>
))
Progress.displayName = ProgressPrimitive.Root.displayName

export { Progress }
